import sys

def main():
    data = sys.stdin.read().split()
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        best = cur = 0
        for ch in data[i]:
            if ch == 'P':
                cur += 1
                if cur > best:
                    best = cur
            else:
                cur = 0
        out.append(str(best))
    print("\n".join(out))

main()
